 public void ForFullMapMeasureGrid_taller_viewport_prefers_more_measures_per_column()        {            const double duration = 16 * ms_per_measure;            var shortViewport = ManiaPreviewColumnLayout.ForFullMapMeasureGrid(duration, ms_per_measure, 360f, 180f);            var tallViewport = ManiaPreviewColumnLayout.ForFullMapMeasureGrid(duration, ms_per_measure, 360f, 520f);            Assert.That(tallViewport.MeasuresPerColumn, Is.GreaterThanOrEqualTo(shortViewport.MeasuresPerColumn));            Assert.That(tallViewport.FitScale, Is.GreaterThan(0f));        }    }}